insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch1-q001', (select id from chapters where code='ch1'), 1, '2025-26 Half Yearly', 1, 'easy', 60, 'mcq', 'Which of the following is a perfect square?', '["6250", "10404", "38943", "12547"]'::jsonb, 1, '(b) 10404, since 10404 = $102^{2}$. (6250, 38943 and 12547 are not perfect squares — note 38943 ends in 3, so it cannot be a square.)');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch1-q002', (select id from chapters where code='ch1'), 2, '2025-26 Half Yearly', 1, 'easy', 60, 'mcq', 'If $\sqrt[3]{636056}$ = 86, then ($\sqrt[3]{636.056}  \times  \sqrt[3]{636056}  \times  \sqrt[3]{0.000636056}$) is', '["63.6056", "636.056", "0.636056", "6.36056"]'::jsonb, 0, '(a) 63.6056. $\sqrt[3]{636.056}$ = 8.6, $\sqrt[3]{636056}$ = 86, $\sqrt[3]{0.000636056}$ = 0.086. Product = 8.6 × 86 × 0.086 = 63.6056');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch1-q003', (select id from chapters where code='ch1'), 3, '2025-26 Annual', 1, 'easy', 60, 'mcq', 'If the cube root of x is 8, then the cube root of 8x is', '["4", "8", "16", "2"]'::jsonb, 2, '(c) 16. ∛x = 8 ⇒ x = 512, so 8x = 4096 and $\sqrt[3]{4096}$ = 16.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch1-q004', (select id from chapters where code='ch1'), 1, '2024-25 Half Yearly', 1, 'easy', 60, 'mcq', 'Which of the following is a perfect square number?', '["$2^{6}  \\times  3^{3}$", "$2^{5}  \\times  7^{2}$", "3 × 2 × $7^{2}$", "11 × $3^{3}$ × 33"]'::jsonb, 3, '(d) 11 × $3^{3}$ × 33 = 11 × $3^{3}$ × 3 × 11 = $11^{2}  \times  3^{4} = \left(11  \times  3^{2}\right)^{2} = 99^{2}$. All prime factors occur in pairs.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch1-q005', (select id from chapters where code='ch1'), 4, '2024-25 Annual', 1, 'easy', 60, 'mcq', 'The least number by which 486 should be divided to make it a perfect square is', '["6", "3", "5", "7"]'::jsonb, 0, '(a) 6. 486 = 2 × $3^{5}$. Dividing by 2 × 3 = 6 gives 81 = $9^{2}$.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch1-q006', (select id from chapters where code='ch1'), 5, '2024-25 Annual', 1, 'easy', 60, 'mcq', 'Which of the following statements is true?', '["There are 5 perfect cubes between 1 and 100", "If $x^{2}$ ends with 5, then $x^{3}$ also ends with 5", "Cube of a one-digit number cannot be a two-digit number", "Cube root of 8 is +2 and -2"]'::jsonb, 1, '(b). If $x^{2}$ ends in 5, then x ends in 5, so $x^{3}$ also ends in 5. (There are only 3 perfect cubes between 1 and 100 — 8, 27, 64; $3^{3}$ = 27 is a two-digit cube; and the cube root of 8 is 2 only.)');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch1-q007', (select id from chapters where code='ch1'), 6, '2023-24 Final', 1, 'easy', 60, 'mcq', 'If $\sqrt{11025}$ = x, then $\sqrt{1.1025}$ = ?', '["x/10", "x", "x/100", "x/1000"]'::jsonb, 2, '(c) x/100. $\sqrt{11025}$ = 105, and $\sqrt{1.1025}$ = 1.05 = $\frac{105}{100}$ = x/100.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch1-q008', (select id from chapters where code='ch1'), 7, '2022-23 Half Yearly', 1, 'easy', 60, 'mcq', 'A square number has 5 digits. Its square root is', '["always a 2-digit number", "always a 2-digit number", "always a 3-digit number", "could be a 2- or a 3-digit number"]'::jsonb, 2, '(c) always a 3-digit number. A 5-digit number lies between 10000 and 99999, so its square root lies between 100 and 316 — always 3 digits. (Options (a) and (b) are identical — a misprint in the original paper.)');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch1-q009', (select id from chapters where code='ch1'), 8, '2022-23 Annual', 1, 'easy', 60, 'mcq', 'Cube of 0.3 is', '["0.27", "2.7", "0.0027", "0.027"]'::jsonb, 3, '(d) 0.027. $\left(0.3\right)^{3}$ = 0.3 × 0.3 × 0.3 = 0.027');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch1-q010', (select id from chapters where code='ch1'), 3, '2021-22 Annual', 1, 'easy', 60, 'mcq', '25% of which of the following perfect cube numbers is equal to the cube root of that number?', '["125", "64", "8", "343"]'::jsonb, 2, '(c) 8. 25% of 8 = 2, and $\sqrt[3]{8}$ = 2.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch1-q011', (select id from chapters where code='ch1'), 9, '2021-22 PT-2', 1, 'easy', 60, 'mcq', 'If one member of a Pythagorean triplet is 12, which of these could be the remaining members?', '["35 and 6", "35 and 37", "37 and 36", "36 and 6"]'::jsonb, 1, '(b) 35 and 37. Using 2m = 12 ⇒ m = 6, giving $m^{2}$ - 1 = 35 and $m^{2}$ + 1 = 37. Check: $12^{2} + 35^{2} = 37^{2}$.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch1-q012', (select id from chapters where code='ch1'), 4, '2021-22 PT-2', 1, 'easy', 60, 'short', 'The prime factorisation of a number is 2 × 3 × 5 × $2^{5}  \times  5^{2}$. To make the number a perfect square we can
 (i) multiply the number by 2 × 3 × 5 (ii) multiply the number by 5 × 3
 (iii) divide the number by 5 × 3 (iv) divide the number by 2 × 3 × 5
(a) (i) and (iv) (b) (i) and (iii) (c) (ii) and (iii) (d) (ii) and (iv)', '[]'::jsonb, null, '(c) (ii) and (iii). The number = $2^{6}$ × 3 × $5^{3}$. Multiplying by 3 × 5 gives $2^{6}  \times  3^{2}  \times  5^{4}$; dividing by 3 × 5 gives $2^{6}  \times  5^{2}$. Both are perfect squares.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch1-q013', (select id from chapters where code='ch1'), 7, '2024-25 PT-2', 1, 'easy', 60, 'short', 'Which digit will be in the unit''s place of the square of 3457?', '[]'::jsonb, null, '9. The unit digit of 3457 is 7, and $7^{2}$ = 49, so the square ends in 9.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch1-q014', (select id from chapters where code='ch1'), 10, '2022-23 Annual', 1, 'easy', 60, 'short', 'The value of $\sqrt{128 - \sqrt{49}}$ is ________.', '[]'::jsonb, null, '11. $\sqrt{49}$ = 7, so $\sqrt{128 - 7} = \sqrt{121}$ = 11.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch1-q015', (select id from chapters where code='ch1'), 11, '2022-23 Annual', 1, 'easy', 60, 'short', 'Using estimation, the cube root of 74088 is ________.', '[]'::jsonb, null, '42. 74088 → last group gives unit digit 2; first group 74 lies between $4^{3}$ = 64 and $5^{3}$ = 125 ⇒ tens digit 4. So $\sqrt[3]{74088}$ = 42.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch1-q016', (select id from chapters where code='ch1'), 12, '2025-26 Half Yearly', 1, 'easy', 60, 'short', 'Evaluate: $\left(141\right)^{2} - \left(140\right)^{2}$', '[]'::jsonb, null, '281. $a^{2} - b^{2}$ = (a + b)(a - b) = (141 + 140)(141 - 140) = 281 × 1 = 281');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch1-q017', (select id from chapters where code='ch1'), 13, '2025-26 Half Yearly', 1, 'easy', 60, 'short', 'Fill in the boxes with the correct numbers:
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch1-q018', (select id from chapters where code='ch1'), 14, '2025-26 Annual', 1, 'easy', 60, 'short', 'A cubical vessel can hold 9261 cubic cm of water when filled to the brim. What is its height?', '[]'::jsonb, null, '21 cm. Height = $\sqrt[3]{9261}$ = 21.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch1-q019', (select id from chapters where code='ch1'), 11, '2025-26 Annual', 1, 'easy', 60, 'short', 'Estimate the cube root of 103823.', '[]'::jsonb, null, '47. ($47^{3}$ = 103823)');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch1-q020', (select id from chapters where code='ch1'), 11, '2024-25 Half Yearly', 1, 'easy', 60, 'short', 'Estimate the length of each side of a cube if its volume is 12167 c$m^{3}$.', '[]'::jsonb, null, '23 cm. Side = $\sqrt[3]{12167}$ = 23.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch1-q021', (select id from chapters where code='ch1'), 6, '2024-25 Half Yearly', 1, 'easy', 60, 'short', 'If $\sqrt{7396}$ = 86, the value of $\sqrt{73960000} + \sqrt{0.007396}$ is ________.', '[]'::jsonb, null, '8600.086. $\sqrt{73960000}$ = 8600 and $\sqrt{0.007396}$ = 0.086.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch1-q022', (select id from chapters where code='ch1'), 11, '2023-24 Final', 1, 'easy', 60, 'short', 'Estimate the cube root of 13824.', '[]'::jsonb, null, '24. ($24^{3}$ = 13824)');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch1-q023', (select id from chapters where code='ch1'), 1, '2022-23 Half Yearly', 1, 'easy', 60, 'short', 'Which of the following is definitely NOT a square number? Justify with a suitable reason.
 (a) 1253687  (b) 2318025', '[]'::jsonb, null, '(a) 1253687 is definitely not a square, because a perfect square can only end in 0, 1, 4, 5, 6 or 9 — never in 2, 3, 7 or 8. This number ends in 7.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch1-q024', (select id from chapters where code='ch1'), 11, '2023-24 PT-2', 1, 'easy', 60, 'short', 'The units digit and the tens digit of $\sqrt[3]{658503}$ are ________ and ________ respectively.', '[]'::jsonb, null, 'Units digit 7, tens digit 8 — $\sqrt[3]{658503}$ = 87.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch1-q025', (select id from chapters where code='ch1'), 12, '2023-24 PT-2', 1, 'easy', 60, 'short', 'Find $23^{2} - 22^{2}$ using a property of square numbers.', '[]'::jsonb, null, '45. For consecutive numbers, $a^{2} - b^{2}$ = a + b when a - b = 1. So $23^{2} - 22^{2}$ = 23 + 22 = 45.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch1-q026', (select id from chapters where code='ch1'), 9, '2023-24 PT-2', 1, 'easy', 60, 'short', 'Find the Pythagorean triplet whose largest member is 26.', '[]'::jsonb, null, '(10, 24, 26). Taking $m^{2}$ + 1 = 26 ⇒ m = 5, so 2m = 10 and $m^{2}$ - 1 = 24. Check: $10^{2} + 24^{2} = 26^{2}$.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch1-q027', (select id from chapters where code='ch1'), 9, '2024-25 PT-2', 2, 'medium', 120, 'short', 'If the hypotenuse of a right-angled triangle is 17, find the lengths of the other two sides.', '[]'::jsonb, null, '8 and 15. Taking $m^{2}$ + 1 = 17 ⇒ m = 4, so 2m = 8 and $m^{2}$ - 1 = 15. Check: $8^{2} + 15^{2}$ = 289 = $17^{2}$.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch1-q028', (select id from chapters where code='ch1'), 9, '2025-26 Half Yearly', 2, 'medium', 120, 'short', 'If one member of a Pythagorean triplet is 65, find the other two members.', '[]'::jsonb, null, '16 and 63. Taking $m^{2}$ + 1 = 65 ⇒ m = 8, so 2m = 16 and $m^{2}$ - 1 = 63. Check: $16^{2} + 63^{2} = 65^{2}$.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch1-q029', (select id from chapters where code='ch1'), 11, '2025-26 Half Yearly', 2, 'medium', 120, 'short', 'Find the cube root of (i) 79507 (using the shortcut method)  (ii) $\frac{27}{3^{9}}$', '[]'::jsonb, null, '(i) 43  (ii) $\frac{27}{3^{9}} = 3^{3}$/$3^{9} = 3^{-6}$, so the cube root is $3^{-2} = \frac{1}{9}$.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch1-q030', (select id from chapters where code='ch1'), 15, '2025-26 Half Yearly', 2, 'medium', 120, 'short', 'Find the value of x, if 1323/x is a perfect cube.', '[]'::jsonb, null, 'x = 49. 1323 = $3^{3}  \times  7^{2}$. Removing $7^{2}$ leaves $3^{3}$ = 27, a perfect cube. So x = 49.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch1-q031', (select id from chapters where code='ch1'), 3, '2024-25 Half Yearly', 2, 'medium', 120, 'short', 'If x = $\sqrt[3]{\left(\frac{27}{64}\right)}$ and y = $\sqrt[3]{\left(\frac{-1}{64}\right)}$, what is x + y?', '[]'::jsonb, null, '$\frac{1}{2}$. x = $\sqrt[3]{\left(\frac{27}{64}\right)} = \frac{3}{4}$ and y = $\sqrt[3]{\left(\frac{-1}{64}\right)} = \frac{-1}{4}$, so x + y = $\frac{3}{4} - \frac{1}{4} = \frac{1}{2}$.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch1-q032', (select id from chapters where code='ch1'), 4, '2024-25 PT-2', 3, 'hard', 210, 'long', 'What is the smallest number by which 8820 must be multiplied to make it a perfect square? Also find the square root of the number so obtained.', '[]'::jsonb, null, 'Multiply by 5; the square root is 210. 8820 = $2^{2}  \times  3^{2}$ × 5 × $7^{2}$. Only 5 is unpaired, so multiply by 5 → 44100 = $210^{2}$.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch1-q033', (select id from chapters where code='ch1'), 16, '2023-24 PT-2', 2, 'medium', 120, 'short', 'Find the smallest number which must be subtracted from 5676 to make it a perfect square. Also find the square root of the perfect square so obtained.', '[]'::jsonb, null, 'Subtract 51; the square root is 75. $75^{2}$ = 5625 and $76^{2}$ = 5776, so 5676 - 5625 = 51.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch1-q034', (select id from chapters where code='ch1'), 2, '2023-24 PT-2', 2, 'medium', 120, 'short', 'Simplify: ($\sqrt[3]{343} + \sqrt[3]{0.343}$) × $\sqrt[3]{10^{6}}$', '[]'::jsonb, null, '770. $\sqrt[3]{343}$ = 7, $\sqrt[3]{0.343}$ = 0.7, $\sqrt[3]{10^{6}}$ = 100. So (7 + 0.7) × 100 = 770.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch1-q035', (select id from chapters where code='ch1'), 4, '2022-23 Half Yearly', 2, 'medium', 120, 'short', 'Find the smallest number by which 2352 must be multiplied to obtain a perfect square. Find the square root of the new number so formed.', '[]'::jsonb, null, 'Multiply by 3; the square root is 84. 2352 = $2^{4}$ × 3 × $7^{2}$. Only 3 is unpaired → 2352 × 3 = 7056 = $84^{2}$.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch1-q036', (select id from chapters where code='ch1'), 6, '2022-23 Half Yearly', 2, 'medium', 120, 'short', 'Find the value of $\sqrt{625} + \sqrt{0.000625} + \sqrt{0.0625}$', '[]'::jsonb, null, '25.275. $\sqrt{625}$ = 25, $\sqrt{0.000625}$ = 0.025, $\sqrt{0.0625}$ = 0.25. Sum = 25.275.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch1-q037', (select id from chapters where code='ch1'), 3, '2021-22 Annual', 1, 'easy', 60, 'short', 'Find the cube root of $\left(18\right)^{3}  \times  \left(\frac{1}{12}\right)^{3}$.', '[]'::jsonb, null, '$\frac{3}{2}$ (= 1.5). $\sqrt[3]{18^{3}  \times  \left(\frac{1}{12}\right)^{3}}$ = 18 × $\frac{1}{12} = \frac{3}{2}$.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch1-q038', (select id from chapters where code='ch1'), 11, '2021-22 Annual', 2, 'medium', 120, 'short', 'Find the cube root of 19683 by estimation.', '[]'::jsonb, null, '27. ($27^{3}$ = 19683)');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch1-q039', (select id from chapters where code='ch1'), 6, '2021-22 PT-2', 2, 'medium', 120, 'short', 'If $\sqrt{3844}$ = 62 and $\sqrt{32.49}$ = 5.7, find the value of $\sqrt{0.3844} - \sqrt{0.003249}$', '[]'::jsonb, null, '0.563. $\sqrt{0.3844}$ = 0.62 and $\sqrt{0.003249}$ = 0.057, so 0.62 - 0.057 = 0.563.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch1-q040', (select id from chapters where code='ch1'), 14, '2024-25 Annual', 2, 'medium', 120, 'short', 'Find the cube root of 17576 by prime factorisation.', '[]'::jsonb, null, '26. 17576 = $2^{3}  \times  13^{3}$, so $\sqrt[3]{17576}$ = 2 × 13 = 26.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch1-q041', (select id from chapters where code='ch1'), 17, '2024-25 Annual', 3, 'hard', 210, 'long', 'Find $\sqrt{20}$ up to two decimal places.', '[]'::jsonb, null, '4.47. ($4.47^{2}$ = 19.9809, and $4.48^{2}$ = 20.0704)');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch1-q042', (select id from chapters where code='ch1'), 6, '2025-26 Half Yearly', 3, 'hard', 210, 'long', 'Using long division, find $\sqrt{691.69}$', '[]'::jsonb, null, '26.3');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch1-q043', (select id from chapters where code='ch1'), 6, '2025-26 Annual', 3, 'hard', 210, 'long', 'Find the square root of 125.44 using the long division method.', '[]'::jsonb, null, '11.2');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch1-q044', (select id from chapters where code='ch1'), 6, '2024-25 Half Yearly', 3, 'hard', 210, 'long', 'Find the square root of 2079.36.', '[]'::jsonb, null, '45.6');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch1-q045', (select id from chapters where code='ch1'), 6, '2023-24 PT-2', 4, 'challenge', 300, 'long', 'Find the square root of 108.16 by the long division method.', '[]'::jsonb, null, '10.4');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch1-q046', (select id from chapters where code='ch1'), 6, '2023-24 Final', 2, 'medium', 120, 'short', 'Find $\sqrt{54.76}$ using the long division method.', '[]'::jsonb, null, '7.4');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch1-q047', (select id from chapters where code='ch1'), 6, '2022-23 Half Yearly', 3, 'hard', 210, 'long', 'Find the square root of 8136.04 by long division.', '[]'::jsonb, null, '90.2');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch1-q048', (select id from chapters where code='ch1'), 18, '2025-26 Half Yearly', 3, 'hard', 210, 'long', 'Find the smallest square number which is divisible by 10, 20 and 28.', '[]'::jsonb, null, '4900 (= $70^{2}$). LCM(10, 20, 28) = 140 = $2^{2}$ × 5 × 7. To make it a square, multiply by 5 × 7 = 35 → 4900.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch1-q049', (select id from chapters where code='ch1'), 15, '2025-26 Half Yearly', 3, 'hard', 210, 'long', 'Is 2560 a perfect cube? If not, find the smallest natural number by which 2560 should be multiplied so that the product is a perfect cube.', '[]'::jsonb, null, 'No, 2560 is not a perfect cube. 2560 = $2^{9}$ × 5. Multiply by $5^{2}$ = 25 → 64000 = $40^{3}$.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch1-q050', (select id from chapters where code='ch1'), 18, '2024-25 Half Yearly', 3, 'hard', 210, 'long', 'Find the smallest perfect cube that is divisible by 4, 9 and 10.', '[]'::jsonb, null, '27000 (= $30^{3}$). LCM(4, 9, 10) = 180 = $2^{2}  \times  3^{2}$ × 5. For a cube each prime needs a power that is a multiple of 3 → $2^{3}  \times  3^{3}  \times  5^{3}$ = 27000.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch1-q051', (select id from chapters where code='ch1'), 18, '2022-23 Half Yearly', 3, 'hard', 210, 'long', 'Find the smallest perfect square number which is exactly divisible by 80, 12, 24 and 36. Also find its square root.', '[]'::jsonb, null, '3600 (= $60^{2}$); square root = 60. LCM(80, 12, 24, 36) = 720 = $2^{4}  \times  3^{2}$ × 5. Only 5 is unpaired → 720 × 5 = 3600.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch1-q052', (select id from chapters where code='ch1'), 15, '2022-23 Annual', 3, 'hard', 210, 'long', 'Find the smallest whole number by which 23625 must be divided so that the quotient is a perfect cube. Also find the cube root of the cube number so obtained.', '[]'::jsonb, null, 'Divide by 7; the cube root is 15. 23625 = $3^{3}  \times  5^{3}$ × 7. Removing 7 gives 3375 = $15^{3}$.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch1-q053', (select id from chapters where code='ch1'), 16, '2021-22 PT-2', 3, 'hard', 210, 'long', 'Find (a) the least number which must be subtracted from 7400 so as to get a perfect square, and (b) the least number which must be added to 7400 so as to get a perfect square.', '[]'::jsonb, null, '(a) Subtract 4. $86^{2}$ = 7396, so 7400 - 7396 = 4.
(b) Add 169. $87^{2}$ = 7569, so 7569 - 7400 = 169.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch1-q054', (select id from chapters where code='ch1'), 12, '2024-25 Half Yearly', 3, 'hard', 210, 'long', '(a) Between $23^{2}$ and $24^{2}$ there are ________ natural numbers.
(b) The square root of the number 161728401 will have ________ digits.
(c) The sum of the first 17 odd natural numbers is ________.', '[]'::jsonb, null, '(a) 46. Between $n^{2}$ and $\left(n + 1\right)^{2}$ there are 2n numbers, so 2 × 23 = 46.
(b) 5 digits. 161728401 has 9 digits, and the square root of an n-digit number has (n + 1)/2 digits when n is odd.
(c) 289. The sum of the first n odd numbers is $n^{2}$, so $17^{2}$ = 289.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch1-q055', (select id from chapters where code='ch1'), 12, '2022-23 Half Yearly', 4, 'challenge', 300, 'long', '(a) Write the Pythagorean triplet whose one of the numbers is 24.
(b) How many natural numbers lie between $18^{2}$ and $19^{2}$?
(c) Express 36 as the sum of consecutive odd numbers.', '[]'::jsonb, null, '(a) (24, 143, 145), using 2m = 24 ⇒ m = 12. (The well-known triplet (7, 24, 25) also contains 24.)
(b) 36. 2 × 18 = 36.
(c) 36 = 1 + 3 + 5 + 7 + 9 + 11 (the first 6 odd numbers, and $6^{2}$ = 36).');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch1-q056', (select id from chapters where code='ch1'), 15, '2023-24 Final', 2, 'medium', 120, 'short', 'Sakshi makes a cuboid of sides 15 cm × 30 cm × 15 cm. How many such cuboids will she need to form a cube?', '[]'::jsonb, null, '4 cuboids. Volume of one cuboid = 15 × 30 × 15 = 6750 = 2 × $3^{3}  \times  5^{3}$. Only 2 is short of a triple, so multiply by $2^{2}$ = 4 → 27000 = $30^{3}$.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch1-q057', (select id from chapters where code='ch1'), 19, '2025-26 Half Yearly', 3, 'hard', 210, 'long', 'Three friends had some money in the ratio 2 : 3 : 4. If the sum of the cubes of the amounts is ₹792, find how much money each of them had.', '[]'::jsonb, null, '₹4, ₹6 and ₹8. Let the amounts be 2x, 3x, 4x. Then 8$x^{3}$ + 27$x^{3}$ + 64$x^{3}$ = 99$x^{3}$ = 792 ⇒ $x^{3}$ = 8 ⇒ x = 2.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch1-q058', (select id from chapters where code='ch1'), 19, '2023-24 PT-2', 3, 'hard', 210, 'long', 'Three numbers are in the ratio 2 : 3 : 4. If the sum of their cubes is 131769, find the three numbers.', '[]'::jsonb, null, '22, 33 and 44. 99$x^{3}$ = 131769 ⇒ $x^{3}$ = 1331 ⇒ x = 11.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch1-q059', (select id from chapters where code='ch1'), 20, '2025-26 Half Yearly', 4, 'challenge', 300, 'long', 'As part of the Independence Day programme, a group of people were arranged so that the number of rows was equal to the number of columns, forming a square formation. If there were 9450 people, how many more persons are required to make this arrangement possible? Also find the number of persons in each row.', '[]'::jsonb, null, '154 more persons; 98 persons in each row. $97^{2}$ = 9409 and $98^{2}$ = 9604, so 9604 - 9450 = 154.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch1-q060', (select id from chapters where code='ch1'), 20, '2024-25 Half Yearly', 3, 'hard', 210, 'long', 'For the Republic Day parade, dancers are to be arranged in a formation such that the number of rows equals the number of columns. There are 2016 dancers in the group.
(a) What is the minimum number of dancers to be added to make this arrangement?
(b) Find the number of dancers in each row.', '[]'::jsonb, null, '(a) 9 dancers. $44^{2}$ = 1936 and $45^{2}$ = 2025, so 2025 - 2016 = 9.
(b) 45 dancers in each row.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch1-q061', (select id from chapters where code='ch1'), 20, '2022-23 Half Yearly', 4, 'challenge', 300, 'long', 'Daisy is decorating flowers in rows such that the number of flowers in one row is equal to the number of rows. She has 5646 flowers. How many more flowers does she need to make such an arrangement? How many flowers does she place in a row?', '[]'::jsonb, null, '130 more flowers; 76 flowers in a row. $75^{2}$ = 5625 and $76^{2}$ = 5776, so 5776 - 5646 = 130.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch1-q062', (select id from chapters where code='ch1'), 20, '2022-23 Annual', 3, 'hard', 210, 'long', 'In a meeting hall there are 13695 chairs. The organiser arranged the chairs so that the number of chairs in each row is equal to the number of rows. Find the least number of chairs left out of this arrangement.', '[]'::jsonb, null, '6 chairs. $117^{2}$ = 13689, and 13695 - 13689 = 6.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch1-q063', (select id from chapters where code='ch1'), 21, '2024-25 Half Yearly', 4, 'challenge', 300, 'long', 'The area of a square ground is 7056 $m^{2}$. Find the perimeter of the square ground. Also find the cost of fencing it at the rate of ₹12 per metre.', '[]'::jsonb, null, 'Perimeter = 336 m; cost = ₹4032. Side = $\sqrt{7056}$ = 84 m, so perimeter = 4 × 84 = 336 m and cost = 336 × 12 = ₹4032.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch2-q001', (select id from chapters where code='ch2'), 22, '2025-26 Annual', 1, 'easy', 60, 'mcq', '$\left(-3p^{-3}\right)^{2}$ = ________', '["-3$p^{-6}$", "9$p^{-6}$", "-9$p^{6}$", "6$p^{6}$"]'::jsonb, 1, '(b) 9$p^{-6}$. $\left(-3p^{-3}\right)^{2} = \left(-3\right)^{2}  \times  \left(p^{-3}\right)^{2}$ = 9$p^{-6}$.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch2-q002', (select id from chapters where code='ch2'), 22, '2025-26 Half Yearly', 1, 'easy', 60, 'mcq', 'The value of $\left(0.03\right)^{-2}  \times  \left(0.000027\right)^{3}$ is', '["$\\left(0.03\\right)^{5}$", "$\\left(0.03\\right)^{7}$", "0.03", "$\\left(0.3\\right)^{7}$"]'::jsonb, 1, '(b) $\left(0.03\right)^{7}$. 0.000027 = $\left(0.03\right)^{3}$, so $\left(0.03\right)^{-2}  \times  \left(0.03\right)^{9} = \left(0.03\right)^{7}$.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch2-q003', (select id from chapters where code='ch2'), 23, '2024-25 Half Yearly', 1, 'easy', 60, 'mcq', 'The value of [ $\left(\frac{2}{3}\right)^{2}  \times  \left(\frac{-1}{3}\right)^{-2}$ ]^{2} is ________', '["$4^{2}$", "$\\left(\\frac{1}{4}\\right)^{2}$", "$\\left(\\frac{4}{81}\\right)^{2}$", "$\\left(\\frac{81}{4}\\right)^{2}$"]'::jsonb, 0, '(a) $4^{2}$. $\left(\frac{2}{3}\right)^{2} = \frac{4}{9}$ and $\left(\frac{-1}{3}\right)^{-2}$ = 9, so the bracket = 4, and $4^{2}$ follows.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch2-q004', (select id from chapters where code='ch2'), 22, '2023-24 Half Yearly', 1, 'easy', 60, 'mcq', 'Which of these is equal to $\left(10\right)^{-6}$?', '["$10^{-3}  \\div  10^{9}$", "$10^{3}  \\div  10^{-9}$", "$10^{3}  \\div  10^{9}$", "$10^{-3}  \\div  10^{-9}$"]'::jsonb, 2, '(c) $10^{3}  \div  10^{9} = 10^{3-9} = 10^{-6}$.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch2-q005', (select id from chapters where code='ch2'), 24, '2022-23 Half Yearly', 1, 'easy', 60, 'mcq', 'What number comes in the blank to make the number sentence true?', '["$\\left(\\frac{-5}{7}\\right)^{-3}$", "$\\left(\\frac{-7}{5}\\right)^{-3}$", "$\\left(\\frac{5}{7}\\right)^{3}$", "$\\left(\\frac{7}{5}\\right)^{3}$"]'::jsonb, 1, '(b) $\left(\frac{-7}{5}\right)^{-3}$. $\left(\frac{7}{-5}\right)^{3} = \left(\frac{-7}{5}\right)^{3}$, and a number times its reciprocal is 1, so the blank is $\left(\frac{-7}{5}\right)^{-3}$.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch2-q006', (select id from chapters where code='ch2'), 25, '2022-23 PT-1', 1, 'easy', 60, 'mcq', 'The value of $1^{-7} + 1^{7} + 1^{0}$ is', '["0", "1", "2", "3"]'::jsonb, 3, '(d) 3. Any power of 1 is 1, so 1 + 1 + 1 = 3.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch2-q007', (select id from chapters where code='ch2'), 23, '2022-23 PT-1', 1, 'easy', 60, 'mcq', 'The value of $x^{-1}  \div  y^{-1}$ is', '["y/x", "x/y", "1/xy", "xy/1"]'::jsonb, 0, '(a) y/x. $x^{-1}  \div  y^{-1} = \left(\frac{1}{x}\right)  \div  \left(\frac{1}{y}\right) = \left(\frac{1}{x}\right)$ × y = y/x.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch2-q008', (select id from chapters where code='ch2'), 26, '2021-22 Half Yearly', 1, 'easy', 60, 'mcq', '($12^{2} - 5^{3}$) × $\left(-1\right)^{20}$/19 equals ________', '["0", "1", "-1", "2"]'::jsonb, 1, '(b) 1. $12^{2} - 5^{3}$ = 144 - 125 = 19, and $\left(-1\right)^{20}$ = 1, so 19 × $\left(\frac{1}{19}\right)$ = 1.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch2-q009', (select id from chapters where code='ch2'), 23, '2021-22 Half Yearly', 1, 'easy', 60, 'mcq', 'If x = $\left(\frac{5}{8}\right)^{-2}  \times  \left(\frac{4}{5}\right)^{-2}$, then the value of $x^{-1}$ is ________', '["$\\frac{1}{4}$", "64", "4", "$\\frac{1}{64}$"]'::jsonb, 0, '(a) $\frac{1}{4}$. $\left(\frac{5}{8}\right)^{-2} = \frac{64}{25}$ and $\left(\frac{4}{5}\right)^{-2} = \frac{25}{16}$, so x = 4 and $x^{-1} = \frac{1}{4}$.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch2-q010', (select id from chapters where code='ch2'), 27, '2021-22 PT-1', 1, 'easy', 60, 'mcq', 'Which of the following statements is true?', '["4.26 × $10^{6}$ = 4260 × $10^{4}$", "4.26 × $10^{5}$ = 42600000", "4.26 × $10^{7}$ = 42600000", "4.26 × $10^{6}$ = 426 × $10^{5}$"]'::jsonb, 2, '(c). 4.26 × $10^{7}$ = 42600000.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch2-q011', (select id from chapters where code='ch2'), 24, '2021-22 PT-1', 1, 'easy', 60, 'mcq', 'The multiplicative inverse of $5^{-2}$ is ________', '["1", "5", "10", "25"]'::jsonb, 3, '(d) 25. $5^{-2} = \frac{1}{25}$, whose multiplicative inverse is 25.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch2-q012', (select id from chapters where code='ch2'), 26, '2023-24 Half Yearly', 1, 'easy', 60, 'short', 'The value of $\left(-2\right)^{0} - \left(-2\right)^{1} + \left(-2\right)^{2} + \left(-2\right)^{3}$ is ________.', '[]'::jsonb, null, '-1. $\left(-2\right)^{0} - \left(-2\right)^{1} + \left(-2\right)^{2} + \left(-2\right)^{3}$ = 1 + 2 + 4 - 8 = -1.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch2-q013', (select id from chapters where code='ch2'), 27, '2025-26 Half Yearly', 1, 'easy', 60, 'short', 'Write 0.00003412652 in standard form.', '[]'::jsonb, null, '3.412652 × $10^{-5}$');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch2-q014', (select id from chapters where code='ch2'), 27, '2021-22 PT-1', 1, 'easy', 60, 'short', 'Express 34500000 in standard form.', '[]'::jsonb, null, '3.45 × $10^{7}$');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch2-q015', (select id from chapters where code='ch2'), 22, '2024-25 Half Yearly', 1, 'easy', 60, 'short', 'Fill in the blank: ________ ÷ $\left(\frac{1}{5}\right)^{-3} = \left(\frac{1}{5}\right)^{2}$', '[]'::jsonb, null, '5. The blank = $\left(\frac{1}{5}\right)^{2}  \times  \left(\frac{1}{5}\right)^{-3} = \left(\frac{1}{5}\right)^{-1}$ = 5.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch2-q016', (select id from chapters where code='ch2'), 23, '2025-26 Annual', 1, 'easy', 60, 'short', 'Find the value of $\left(1^{-1} - 3^{-1}\right)^{-1}$.', '[]'::jsonb, null, '$\frac{3}{2}$. $1^{-1}$ = 1 and $3^{-1} = \frac{1}{3}$, so $\left(1 - \frac{1}{3}\right)^{-1} = \left(\frac{2}{3}\right)^{-1} = \frac{3}{2}$.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch2-q017', (select id from chapters where code='ch2'), 28, '2024-25 Annual', 1, 'easy', 60, 'short', 'Two steel rods weigh 15 × $10^{3}$ kg and 2.6 × $10^{2}$ kg respectively. Find the total weight of the rods.', '[]'::jsonb, null, '15260 kg (= 1.526 × $10^{4}$ kg). 15 × $10^{3}$ = 15000 and 2.6 × $10^{2}$ = 260.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch2-q018', (select id from chapters where code='ch2'), 29, '2024-25 Annual', 1, 'easy', 60, 'short', 'If (5$x^{a}$)(b$x^{2}$) = 35$x^{8}$, find the values of a and b (where a and b are natural numbers).', '[]'::jsonb, null, 'a = 6, b = 7. 5b × $x^{a+2}$ = 35$x^{8}$ ⇒ 5b = 35 ⇒ b = 7, and a + 2 = 8 ⇒ a = 6.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch2-q019', (select id from chapters where code='ch2'), 25, '2022-23 Half Yearly', 1, 'easy', 60, 'short', 'Find the value of $5^{-1}$($5^{0} + 6^{0} + 7^{0}$) + $5^{-1}$.', '[]'::jsonb, null, '$\frac{4}{5}$. Any non-zero number to the power 0 is 1, so $5^{-1}$(1 + 1 + 1) + $5^{-1} = \frac{3}{5} + \frac{1}{5} = \frac{4}{5}$.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch2-q020', (select id from chapters where code='ch2'), 22, '2021-22 PT-1', 2, 'medium', 120, 'short', 'Simplify: $\left(\frac{24}{3}\right)^{4}  \times  \left(\frac{3}{8}\right)^{4}$', '[]'::jsonb, null, '81. $\left(\frac{24}{3}\right)$ = 8, so $8^{4}  \times  \left(\frac{3}{8}\right)^{4} = \left(8  \times  \frac{3}{8}\right)^{4} = 3^{4}$ = 81.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch2-q021', (select id from chapters where code='ch2'), 23, '2023-24 Half Yearly', 2, 'medium', 120, 'short', 'Simplify: $2^{-5} - 8^{-2} + 2^{-3}$', '[]'::jsonb, null, '$\frac{9}{64}$. $2^{-5} = \frac{1}{32}$, $8^{-2} = \frac{1}{64}$, $2^{-3} = \frac{1}{8}$. So $\frac{2}{64} - \frac{1}{64} + \frac{8}{64} = \frac{9}{64}$.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch2-q022', (select id from chapters where code='ch2'), 22, '2022-23 Half Yearly', 2, 'medium', 120, 'short', 'Evaluate: [ $\left(\frac{-2}{3}\right)^{3}  \times  \left(\frac{-2}{3}\right)$ ] ÷ $\left(\frac{4}{9}\right)^{2}$', '[]'::jsonb, null, '1. $\left(\frac{-2}{3}\right)^{3}  \times  \left(\frac{-2}{3}\right) = \left(\frac{-2}{3}\right)^{4} = \frac{16}{81}$, and $\left(\frac{4}{9}\right)^{2} = \frac{16}{81}$. So the quotient is 1.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch2-q023', (select id from chapters where code='ch2'), 22, '2024-25 Annual', 2, 'medium', 120, 'short', 'Evaluate: [ $\left(5^{2}\right)^{-1}$ × 125 ] ÷ $\left(\frac{1}{5}\right)^{-2}$', '[]'::jsonb, null, '$\frac{1}{5}$. $\left(5^{2}\right)^{-1}$ × 125 = $5^{-2}  \times  5^{3}$ = 5, and $\left(\frac{1}{5}\right)^{-2}$ = 25. So 5 ÷ 25 = $\frac{1}{5}$.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch2-q024', (select id from chapters where code='ch2'), 22, '2025-26 Half Yearly', 2, 'medium', 120, 'short', 'Simplify: ($p^{7}$ $q^{2}$ $r^{-4}$) / ($r^{-8}$ $p^{3}$ $q^{-2}$)', '[]'::jsonb, null, '$p^{4}$ $q^{4}$ $r^{4}$. Subtract exponents: $p^{7-3}$ $q^{2-(-2)}$ $r^{-4-(-8)} = p^{4}$ $q^{4}$ $r^{4}$.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch2-q025', (select id from chapters where code='ch2'), 29, '2025-26 Half Yearly', 2, 'medium', 120, 'short', 'Find the value of x:  $5^{-8}  \times  \left(5^{3}\right)^{x} = 25^{3}  \times  5^{x}$', '[]'::jsonb, null, 'x = 7. LHS = $5^{-8+3x}$, RHS = $5^{6+x}$. So -8 + 3x = 6 + x ⇒ 2x = 14 ⇒ x = 7.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch2-q026', (select id from chapters where code='ch2'), 29, '2023-24 Half Yearly', 2, 'medium', 120, 'short', 'Find the value of p if  $12^{p}  \times  12^{-3} = \left(\frac{1}{12}\right)^{-5}$', '[]'::jsonb, null, 'p = 8. $\left(\frac{1}{12}\right)^{-5} = 12^{5}$, so $12^{p-3} = 12^{5}$ ⇒ p = 8.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch2-q027', (select id from chapters where code='ch2'), 29, '2022-23 PT-1', 2, 'medium', 120, 'short', 'Find the value of x if  $\left(\frac{4}{5}\right)^{3}  \div  \left(\frac{5}{4}\right)^{3} = \left(\frac{4}{5}\right)^{3x}$', '[]'::jsonb, null, 'x = 2. $\left(\frac{5}{4}\right)^{3} = \left(\frac{4}{5}\right)^{-3}$, so LHS = $\left(\frac{4}{5}\right)^{3-(-3)} = \left(\frac{4}{5}\right)^{6}$. Hence 3x = 6 ⇒ x = 2.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch2-q028', (select id from chapters where code='ch2'), 29, '2022-23 Half Yearly', 2, 'medium', 120, 'short', 'Find the value of x:  [ $\left(\frac{2}{5}\right)^{-2}$ ]^{2x} = $\frac{625}{16}$', '[]'::jsonb, null, 'x = 1. $\left(\frac{2}{5}\right)^{-2} = \frac{25}{4}$, and $\frac{625}{16} = \left(\frac{25}{4}\right)^{2}$. So 2x = 2 ⇒ x = 1.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch2-q029', (select id from chapters where code='ch2'), 23, '2021-22 Half Yearly', 2, 'medium', 120, 'short', 'If a/b = $\left(\frac{2}{3}\right)^{-3}  \times  \left(\frac{5}{6}\right)^{0}$, find the value of $\left(\frac{a}{b}\right)^{-2}$.', '[]'::jsonb, null, '$\frac{64}{729}$. a/b = $\left(\frac{3}{2}\right)^{3}$ × 1 = $\frac{27}{8}$, so $\left(\frac{a}{b}\right)^{-2} = \left(\frac{8}{27}\right)^{2} = \frac{64}{729}$.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch2-q030', (select id from chapters where code='ch2'), 29, '2025-26 Annual', 2, 'medium', 120, 'short', 'Find x, if  $\left(\frac{5}{9}\right)^{2x}  \times  \left(\frac{5}{9}\right)^{-18} = \left(\frac{81}{25}\right)^{-3}$', '[]'::jsonb, null, 'x = 12. $\left(\frac{81}{25}\right)^{-3} = \left(\frac{25}{81}\right)^{3} = \left(\frac{5}{9}\right)^{6}$, and LHS = $\left(\frac{5}{9}\right)^{2x-18}$. So 2x - 18 = 6 ⇒ x = 12.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch2-q031', (select id from chapters where code='ch2'), 29, '2024-25 Half Yearly', 3, 'hard', 210, 'long', 'Find the value of x using the laws of exponents:
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch2-q032', (select id from chapters where code='ch2'), 22, '2022-23 Half Yearly', 3, 'hard', 210, 'long', 'Simplify using the laws of exponents:  (125 × $6^{6}  \times  10^{4}$) / ($5^{7}  \times  9^{3}  \times  8^{2}$)', '[]'::jsonb, null, '16. Numerator = $5^{3}  \times  2^{6}$$3^{6}  \times  2^{4}$$5^{4} = 2^{10}$ $3^{6}$ $5^{7}$; denominator = $5^{7}  \times  3^{6}  \times  2^{6}$. So the result is $2^{4}$ = 16.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch2-q033', (select id from chapters where code='ch2'), 22, '2022-23 Half Yearly', 3, 'hard', 210, 'long', 'P = [ $\left(\frac{4}{9}\right)^{-2}  \times  \left(\frac{3}{4}\right)^{-2}$ ] × $\frac{1}{3^{-2}}  \times  \left(\frac{17}{39}\right)^{0}$.
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch2-q034', (select id from chapters where code='ch2'), 22, '2022-23 PT-1', 3, 'hard', 210, 'long', 'Simplify using the laws of exponents and state the laws used:
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch2-q035', (select id from chapters where code='ch2'), 22, '2023-24 Half Yearly', 3, 'hard', 210, 'long', 'Simplify using the laws of exponents and state the laws used:
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch2-q036', (select id from chapters where code='ch2'), 29, '2023-24 Half Yearly', 4, 'challenge', 300, 'long', 'Simplify using the laws of exponents and find the value of x. Mention the laws used.
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch2-q037', (select id from chapters where code='ch2'), 22, '2021-22 PT-1', 4, 'challenge', 300, 'long', 'State the law of exponents used in each, and:
(a) Simplify: $\left(3^{9}\right)^{2}  \times  3^{-15}$
(b) Find the value of $x^{-12}$, if $\left(\frac{2}{3}\right)^{4}  \div  \left(\frac{2}{3}\right)^{6} = \left(\frac{2}{3}\right)^{2x}$', '[]'::jsonb, null, '(a) 27. $\left(3^{9}\right)^{2}  \times  3^{-15} = 3^{18-15} = 3^{3}$ = 27. Laws: $\left(a^{m}\right)^{n} = a^{mn}$ and $a^{m}  \times  a^{n} = a^{m+n}$.
(b) 1. $\left(\frac{2}{3}\right)^{4-6} = \left(\frac{2}{3}\right)^{-2}$, so 2x = -2 ⇒ x = -1, and $x^{-12} = \left(-1\right)^{-12}$ = 1.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch2-q038', (select id from chapters where code='ch2'), 30, '2025-26 Half Yearly', 4, 'challenge', 300, 'long', 'Evaluate:
(a) $\left(\frac{8}{27}\right)^{2/3}  \div  \left(32\right)^{\frac{-2}{5}}$
(b) $2^{4}$ - [ $\left(\sqrt{4}\right)^{0}  \times  \left(-2\right)^{6}$ ] ÷ 4', '[]'::jsonb, null, '(a) $\frac{16}{9}$. $\left(\frac{8}{27}\right)^{2/3} = \left(\frac{2}{3}\right)^{2} = \frac{4}{9}$, and $32^{\frac{-2}{5}} = 2^{-2} = \frac{1}{4}$. So $\left(\frac{4}{9}\right)  \div  \left(\frac{1}{4}\right) = \frac{16}{9}$.
(b) 0. $2^{4}$ = 16; $\left(\sqrt{4}\right)^{0}$ = 1 and $\left(-2\right)^{6}$ = 64, so [1 × 64] ÷ 4 = 16. Hence 16 - 16 = 0.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch2-q039', (select id from chapters where code='ch2'), 28, '2021-22 Half Yearly', 3, 'hard', 210, 'long', '(i) Subtract 1.73 × $10^{11}$ - 5.46 × $10^{8}$ and express the difference in standard form.
(ii) Find x, if $7^{2x}  \div  7^{-3} = 7^{23}$', '[]'::jsonb, null, '(i) 1.72454 × $10^{11}$. 1.73 × $10^{11}$ - 5.46 × $10^{8}$ = (1730 - 5.46) × $10^{8}$ = 1724.54 × $10^{8}$.
(ii) x = 10. 2x - (-3) = 23 ⇒ 2x = 20 ⇒ x = 10.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch2-q040', (select id from chapters where code='ch2'), 28, '2023-24 Half Yearly', 3, 'hard', 210, 'long', 'Simplify and express in scientific notation:  1.987 × $10^{11}$ - 6.54 × $10^{8}$', '[]'::jsonb, null, '1.98046 × $10^{11}$. (1987 - 6.54) × $10^{8}$ = 1980.46 × $10^{8}$.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch2-q041', (select id from chapters where code='ch2'), 28, '2025-26 Half Yearly', 3, 'hard', 210, 'long', 'The total land area of India is 3.287263 × $10^{12}$ $m^{2}$. If the land area of the southern part of India is 6.3578 × $10^{11}$ $m^{2}$ and the northern part covers 2.3893 × $10^{12}$ $m^{2}$, find the remaining land area in standard form.', '[]'::jsonb, null, '2.62183 × $10^{11}$ $m^{2}$. Southern + northern = 0.63578 × $10^{12}$ + 2.3893 × $10^{12}$ = 3.02508 × $10^{12}$. Remaining = 3.287263 × $10^{12}$ - 3.02508 × $10^{12}$ = 0.262183 × $10^{12}$.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch2-q042', (select id from chapters where code='ch2'), 28, '2024-25 Half Yearly', 4, 'challenge', 300, 'long', '(a) The Moon and Mars are at a distance of 3.844 × $10^{5}$ km and 5.45 × $10^{9}$ m from the Earth respectively. Which is farther from the Earth, and by how much?
(b) The mass of the Earth is 6.512 × $10^{24}$ kg and the mass of the Moon is 7.4 × $10^{22}$ kg approximately. How many times the mass of the Moon is the mass of the Earth?', '[]'::jsonb, null, '(a) Mars is farther, by 5.0656 × $10^{9}$ m. The Moon is 3.844 × $10^{5}$ km = 3.844 × $10^{8}$ m, so 5.45 × $10^{9}$ - 0.3844 × $10^{9}$ = 5.0656 × $10^{9}$ m.
(b) About 88 times. (6.512 × $10^{24}$) ÷ (7.4 × $10^{22}$) = 0.88 × $10^{2}$ = 88.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch2-q043', (select id from chapters where code='ch2'), 28, '2025-26 Annual', 3, 'hard', 210, 'long', 'A particular star is at about 810000000 × $10^{8}$ m away from the Earth. Given that light travels at 3 × $10^{8}$ m per second:
(a) Express the distance of the star from the Earth in scientific notation.
(b) Express the speed of light in usual form.
(c) How long does light take from that star to reach the Earth? Write this in scientific notation.', '[]'::jsonb, null, '(a) 8.1 × $10^{16}$ m. 810000000 × $10^{8}$ = 8.1 × $10^{8}  \times  10^{8}$.
(b) 300000000 m/s.
(c) 2.7 × $10^{8}$ seconds. Time = distance ÷ speed = (8.1 × $10^{16}$) ÷ (3 × $10^{8}$).');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, options_latex, correct_option, answer_latex) values ('ch2-q044', (select id from chapters where code='ch2'), 27, '2022-23 Half Yearly', 4, 'challenge', 300, 'long', 'CASE STUDY — John came up with interesting facts about very large and very small objects. Study the data and answer:
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q001'), 1, 'A perfect square can only end in 0, 1, 4, 5, 6 or 9.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q001'), 2, '6250 ends in 0 but has an odd number of zeros — a square must end in an even number of zeros. 38943 ends in 3 and 12547 ends in 7, so neither can be a square.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q001'), 3, 'That leaves 10404. Check: $102^{2}$ = 10404. ✔');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q001'), 4, 'Answer: (b) 10404');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q002'), 1, 'We are told $\sqrt[3]{636056}$ = 86. The book shows how to CUBE a decimal (p.13); read that backwards — cubing shifts the decimal 3 places, so a cube root shifts it back 1 place for every 3.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q002'), 2, '$\sqrt[3]{636.056}$ = 8.6   (decimal moved 3 places left ⇒ root moved 1 place left)');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q002'), 3, '$\sqrt[3]{636056}$ = 86');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q002'), 4, '$\sqrt[3]{0.000636056}$ = 0.086   (decimal moved 6 places left ⇒ root moved 2 places left)');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q002'), 5, 'Product = 8.6 × 86 × 0.086 = 63.6056');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q002'), 6, 'Answer: (a) 63.6056');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q003'), 1, '∛x = 8, so x = $8^{3}$ = 512.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q003'), 2, 'Then 8x = 8 × 512 = 4096.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q003'), 3, '$\sqrt[3]{4096}$ = 16   (since $16^{3}$ = 4096)');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q003'), 4, 'Answer: (c) 16');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q004'), 1, 'For a perfect square, every prime factor must appear an even number of times.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q004'), 2, '(a) $2^{6}  \times  3^{3}$ — the power of 3 is odd. ✘');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q004'), 3, '(b) $2^{5}  \times  7^{2}$ — the power of 2 is odd. ✘');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q004'), 4, '(c) 3 × 2 × $7^{2}$ — the powers of 3 and 2 are odd. ✘');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q004'), 5, '(d) 11 × $3^{3}$ × 33. Note 33 = 3 × 11, so this is 11 × $3^{3}$ × 3 × 11 = $11^{2}  \times  3^{4}$. Both powers are even. ✔');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q004'), 6, 'In fact $11^{2}  \times  3^{4} = \left(11  \times  3^{2}\right)^{2} = 99^{2}$.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q004'), 7, 'Answer: (d)');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q005'), 1, 'Prime factorise: 486 = 2 × 243 = 2 × $3^{5}$.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q005'), 2, 'For a perfect square each prime needs an even power. Here 2 has power 1 (odd) and 3 has power 5 (odd).');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q005'), 3, 'Divide out one 2 and one 3, i.e. divide by 2 × 3 = 6.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q005'), 4, '486 ÷ 6 = 81 = $9^{2}$. ✔');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q005'), 5, 'Answer: (a) 6');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q006'), 1, 'Test each statement.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q006'), 2, '(a) The perfect cubes below 100 are 1, 8, 27 and 64 — so there are not 5 of them. ✘');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q006'), 3, '(b) If $x^{2}$ ends in 5, then x itself must end in 5 (only numbers ending in 5 have squares ending in 5). And any number ending in 5, when cubed, still ends in 5. ✔');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q006'), 4, '(c) $3^{3}$ = 27 is a two-digit cube of a one-digit number. ✘');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q006'), 5, '(d) The cube root of 8 is 2 only — a cube root has just one value, unlike a square root. ✘');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q006'), 6, 'Answer: (b)');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q007'), 1, '$\sqrt{11025}$ = x, and in fact $105^{2}$ = 11025, so x = 105.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q007'), 2, 'Now 1.1025 = 11025 ÷ 10000.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q007'), 3, 'So $\sqrt{1.1025} = \sqrt{11025}  \div  \sqrt{10000}$ = 105 ÷ 100.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q007'), 4, 'That is x/100.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q007'), 5, 'Answer: (c) x/100');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q008'), 1, 'The smallest 5-digit number is 10000 and the largest is 99999.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q008'), 2, '$\sqrt{10000}$ = 100 and $\sqrt{99999}$ ≈ 316.2');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q008'), 3, 'So the square root lies between 100 and 316 — every number in that range has 3 digits.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q008'), 4, '(Note: options (a) and (b) are printed identically in the original paper — a misprint.)');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q008'), 5, 'Answer: (c) always a 3-digit number');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q009'), 1, 'Cube of 0.3 means $\left(0.3\right)^{3}$ = 0.3 × 0.3 × 0.3.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q009'), 2, '0.3 × 0.3 = 0.09; then 0.09 × 0.3 = 0.027.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q009'), 3, 'Shortcut: $3^{3}$ = 27, and there are 3 decimal places in total (1 from each 0.3), so the answer is 0.027.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q009'), 4, 'Answer: (d) 0.027');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q010'), 1, 'We need a perfect cube n where 25% of n equals ∛n, i.e. n/4 = ∛n.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q010'), 2, 'Try each option:');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q010'), 3, '125: 25% = 31.25, but $\sqrt[3]{125}$ = 5. ✘');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q010'), 4, '64: 25% = 16, but $\sqrt[3]{64}$ = 4. ✘');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q010'), 5, '8: 25% = 2, and $\sqrt[3]{8}$ = 2. ✔');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q010'), 6, '343: 25% = 85.75, but $\sqrt[3]{343}$ = 7. ✘');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q010'), 7, 'Answer: (c) 8');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q011'), 1, '⚠ Note: ''Pythagorean triplets'' are NOT in your Ganita Prakash chapter. But you can still do this using only squares (which are) plus Pythagoras'' theorem from geometry: a triplet is three numbers with $a^{2} + b^{2} = c^{2}$.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q011'), 2, 'Since it is multiple choice, just test the options with the squares table.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q011'), 3, '$12^{2}$ = 144.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q011'), 4, '(b) 35 and 37:  144 + $35^{2}$ = 144 + 1225 = 1369.  Is 1369 a square?  $37^{2}$ = 1369 ✔');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q011'), 5, 'So 12, 35, 37 works. (Checking the others: 6, 35, 36 and 36, 37 do not satisfy $a^{2} + b^{2} = c^{2}$.)');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q011'), 6, 'Answer: (b) 35 and 37');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q012'), 1, 'First tidy the factorisation: 2 × 3 × 5 × $2^{5}  \times  5^{2} = 2^{6}  \times  3^{1}  \times  5^{3}$.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q012'), 2, 'For a perfect square every power must be even. Here $2^{6}$ is fine, but $3^{1}$ and $5^{3}$ have odd powers.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q012'), 3, 'Option A — multiply by 3 × 5: gives $2^{6}  \times  3^{2}  \times  5^{4}$. All powers even. ✔ (that is statement (ii))');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q012'), 4, 'Option B — divide by 3 × 5: gives $2^{6}  \times  5^{2}$. All powers even. ✔ (that is statement (iii))');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q012'), 5, 'Answer: (c) (ii) and (iii)');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q013'), 1, 'Only the unit digit of the number affects the unit digit of its square.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q013'), 2, 'The unit digit of 3457 is 7, and $7^{2}$ = 49, which ends in 9.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q013'), 3, 'Answer: 9');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q014'), 1, 'Work from the inside outwards.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q014'), 2, '$\sqrt{49}$ = 7');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q014'), 3, 'So the expression becomes $\sqrt{128 - 7} = \sqrt{121.}$');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q014'), 4, '$\sqrt{121}$ = 11');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q014'), 5, 'Answer: 11');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q015'), 1, 'Split 74088 into groups of three digits from the right: 74 | 088.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q015'), 2, 'The last group ends in 8. Only $2^{3}$ = 8 ends in 8, so the unit digit of the cube root is 2.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q015'), 3, 'The first group is 74, which lies between $4^{3}$ = 64 and $5^{3}$ = 125. Take the smaller, so the tens digit is 4.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q015'), 4, 'So $\sqrt[3]{74088}$ = 42.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q015'), 5, 'Answer: 42');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q016'), 1, 'Use the identity $a^{2} - b^{2}$ = (a + b)(a - b).');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q016'), 2, '$\left(141\right)^{2} - \left(140\right)^{2}$ = (141 + 140)(141 - 140)');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q016'), 3, '= 281 × 1 = 281');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q016'), 4, 'Answer: 281');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q017'), 1, 'The pattern here is: the cube of n is the sum of n consecutive odd numbers.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q017'), 2, 'The paper already gives two of the odd numbers, 23 and 27, with gaps between and around them — so we need 5 consecutive odd numbers: 21, 23, 25, 27, 29.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q017'), 3, 'Add them: 21 + 23 + 25 + 27 + 29 = 125.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q017'), 4, 'And 125 = $5^{3}$. ✔');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q017'), 5, 'Answer: 21 + 23 + 25 + 27 + 29 = $5^{3}$');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q018'), 1, 'A cube of side a has volume $a^{3}$, so the height is $\sqrt[3]{9261.}$');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q018'), 2, 'Prime factorise: 9261 = 3 × 3087 = 3 × 3 × 1029 = 3 × 3 × 3 × 343 = $3^{3}  \times  7^{3}$.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q018'), 3, '$\sqrt[3]{9261}$ = 3 × 7 = 21');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q018'), 4, 'Answer: 21 cm');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q019'), 1, 'Group into threes from the right: 103 | 823.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q019'), 2, 'The last group ends in 3. Only $7^{3}$ = 343 ends in 3, so the unit digit is 7.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q019'), 3, 'The first group is 103, which lies between $4^{3}$ = 64 and $5^{3}$ = 125. Take the smaller, so the tens digit is 4.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q019'), 4, '$\sqrt[3]{103823}$ = 47');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q019'), 5, 'Answer: 47');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q020'), 1, 'Volume of a cube = $\left(side\right)^{3}$, so side = $\sqrt[3]{12167.}$');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q020'), 2, 'Group into threes: 12 | 167. The last group ends in 7, and only $3^{3}$ = 27 ends in 7 ⇒ unit digit 3.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q020'), 3, 'The first group 12 lies between $2^{3}$ = 8 and $3^{3}$ = 27 ⇒ tens digit 2.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q020'), 4, '$\sqrt[3]{12167}$ = 23');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q020'), 5, 'Answer: 23 cm');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q021'), 1, 'Given $\sqrt{7396}$ = 86. Squaring a decimal doubles its number of decimal places (p.13), so a square root halves them — always check by squaring your answer back.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q021'), 2, '$\sqrt{73960000}$ = 8600   (73960000 = 7396 × 10000, and $\sqrt{10000}$ = 100, so 86 × 100)');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q021'), 3, '$\sqrt{0.007396}$ = 0.086   (0.007396 = 7396 ÷ $10^{6}$, and $\sqrt{10^{6}}$ = 1000, so 86 ÷ 1000)');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q021'), 4, 'Sum = 8600 + 0.086 = 8600.086');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q021'), 5, 'Answer: 8600.086');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q022'), 1, 'Group into threes from the right: 13 | 824.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q022'), 2, 'The last group ends in 4. Only $4^{3}$ = 64 ends in 4, so the unit digit is 4.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q022'), 3, 'The first group 13 lies between $2^{3}$ = 8 and $3^{3}$ = 27 ⇒ tens digit 2.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q022'), 4, '$\sqrt[3]{13824}$ = 24');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q022'), 5, 'Answer: 24');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q023'), 1, 'A perfect square can only end in 0, 1, 4, 5, 6 or 9 — never in 2, 3, 7 or 8.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q023'), 2, '1253687 ends in 7, so it can never be a perfect square. ✔ This is the answer.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q023'), 3, '2318025 ends in 5, so the digit test does not rule it out — we cannot call it ''definitely not'' a square from the unit digit alone.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q023'), 4, 'Answer: (a) 1253687, because a perfect square never ends in 7.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q024'), 1, 'Group 658503 into threes from the right: 658 | 503.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q024'), 2, 'The last group ends in 3. Only $7^{3}$ = 343 ends in 3 ⇒ the unit digit of the cube root is 7.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q024'), 3, 'The first group 658 lies between $8^{3}$ = 512 and $9^{3}$ = 729. Take the smaller ⇒ the tens digit is 8.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q024'), 4, 'So $\sqrt[3]{658503}$ = 87.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q024'), 5, 'Answer: units digit 7, tens digit 8');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q025'), 1, 'Use $a^{2} - b^{2}$ = (a + b)(a - b).');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q025'), 2, '$23^{2} - 22^{2}$ = (23 + 22)(23 - 22) = 45 × 1');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q025'), 3, 'In general, for two consecutive numbers the difference of their squares is simply their sum.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q025'), 4, 'Answer: 45');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q026'), 1, '⚠ Note: triplets are not in your chapter, but this needs only squares plus $a^{2} + b^{2} = c^{2}$.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q026'), 2, 'The largest member is the hypotenuse, so $a^{2} + b^{2} = 26^{2}$ = 676.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q026'), 3, 'Hunt through the squares table for two squares that add to 676:');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q026'), 4, '676 - $10^{2}$ = 676 - 100 = 576, and 576 = $24^{2}$ ✔');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q026'), 5, 'So the triplet is 10, 24, 26.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q026'), 6, 'Answer: (10, 24, 26)');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q027'), 1, '⚠ Note: triplets are not in your chapter, but this needs only squares plus $a^{2} + b^{2} = c^{2}$.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q027'), 2, 'The hypotenuse is the largest side, so $a^{2} + b^{2} = 17^{2}$ = 289.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q027'), 3, 'Hunt through the squares table for two squares adding to 289:');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q027'), 4, '289 - $8^{2}$ = 289 - 64 = 225, and 225 = $15^{2}$ ✔');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q027'), 5, 'So the other two sides are 8 and 15.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q027'), 6, 'Answer: 8 and 15');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q028'), 1, '⚠ Note: triplets are not in your chapter, but this needs only squares plus $a^{2} + b^{2} = c^{2}$.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q028'), 2, 'Take 65 as the largest member, so $a^{2} + b^{2} = 65^{2}$ = 4225.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q028'), 3, 'Hunt for two squares adding to 4225:');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q028'), 4, '4225 - $16^{2}$ = 4225 - 256 = 3969, and 3969 = $63^{2}$ ✔');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q028'), 5, 'So the other two members are 16 and 63.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q028'), 6, '(Curiously 65 belongs to several triplets — (25, 60, 65), (33, 56, 65) and (39, 52, 65) all work too. The one the paper wants is 16 and 63.)');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q028'), 7, 'Answer: 16 and 63');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q029'), 1, '(i) $\sqrt[3]{79507}$ — group into threes: 79 | 507.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q029'), 2, 'The last group ends in 7 ⇒ unit digit is 3 (since $3^{3}$ = 27 ends in 7).');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q029'), 3, 'The first group 79 lies between $4^{3}$ = 64 and $5^{3}$ = 125 ⇒ tens digit 4.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q029'), 4, 'So $\sqrt[3]{79507}$ = 43.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q029'), 5, '(ii) $\frac{27}{3^{9}}$. Write 27 as $3^{3}$:  $3^{3}$/$3^{9} = 3^{3-9} = 3^{-6}$.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q029'), 6, '$\sqrt[3]{3^{-6}} = 3^{\frac{-6}{3}} = 3^{-2} = \frac{1}{9}$');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q029'), 7, 'Answer: (i) 43   (ii) $\frac{1}{9}$');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q030'), 1, 'Prime factorise 1323: 1323 = 3 × 441 = 3 × $21^{2}$ = 3 × $3^{2}  \times  7^{2} = 3^{3}  \times  7^{2}$.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q030'), 2, 'For 1323/x to be a perfect cube, every prime power left behind must be a multiple of 3.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q030'), 3, '$3^{3}$ is already fine. The $7^{2}$ is the problem — it must be removed entirely.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q030'), 4, 'So x = $7^{2}$ = 49, leaving $\frac{1323}{49}$ = 27 = $3^{3}$. ✔');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q030'), 5, 'Answer: x = 49');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q031'), 1, 'x = $\sqrt[3]{\left(\frac{27}{64}\right)}$. Since 27 = $3^{3}$ and 64 = $4^{3}$, x = $\frac{3}{4}$.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q031'), 2, 'y = $\sqrt[3]{\left(\frac{-1}{64}\right)}$. Since -1 = $\left(-1\right)^{3}$ and 64 = $4^{3}$, y = $\frac{-1}{4}$.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q031'), 3, '(A cube root of a negative number is negative — unlike a square root.)');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q031'), 4, 'x + y = $\frac{3}{4} + \left(\frac{-1}{4}\right) = \frac{2}{4} = \frac{1}{2}$');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q031'), 5, 'Answer: $\frac{1}{2}$');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q032'), 1, 'Prime factorise 8820:');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q032'), 2, '8820 = 2 × 4410 = 2 × 2 × 2205 = 4 × 2205, and 2205 = 5 × 441 = 5 × $21^{2}$.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q032'), 3, 'So 8820 = $2^{2}  \times  3^{2}  \times  5^{1}  \times  7^{2}$.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q032'), 4, 'Pair up the factors: $2^{2}$ ✔, $3^{2}$ ✔, $7^{2}$ ✔ — but 5 appears only once.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q032'), 5, 'So multiply by 5:  8820 × 5 = 44100.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q032'), 6, '$\sqrt{44100}$ = 2 × 3 × 5 × 7 = 210');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q032'), 7, 'Answer: multiply by 5; the square root is 210');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q033'), 1, 'Find the largest perfect square below 5676.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q033'), 2, '$75^{2}$ = 5625 and $76^{2}$ = 5776 (which is already bigger than 5676).');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q033'), 3, 'So the nearest square below is 5625.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q033'), 4, '5676 - 5625 = 51');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q033'), 5, 'Subtracting 51 gives 5625, and $\sqrt{5625}$ = 75.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q033'), 6, 'Answer: subtract 51; the square root is 75');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q034'), 1, 'Take each cube root separately.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q034'), 2, '$\sqrt[3]{343}$ = 7   ($7^{3}$ = 343)');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q034'), 3, '$\sqrt[3]{0.343}$ = 0.7   ($0.7^{3}$ = 0.343)');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q034'), 4, '$\sqrt[3]{10^{6}} = 10^{\frac{6}{3}} = 10^{2}$ = 100');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q034'), 5, 'So the expression = (7 + 0.7) × 100 = 7.7 × 100 = 770');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q034'), 6, 'Answer: 770');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q035'), 1, 'Prime factorise 2352:');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q035'), 2, '2352 = 2 × 1176 = 4 × 588 = 8 × 294 = 16 × 147, and 147 = 3 × 49.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q035'), 3, 'So 2352 = $2^{4}  \times  3^{1}  \times  7^{2}$.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q035'), 4, 'Pairs: $2^{4}$ ✔, $7^{2}$ ✔ — but 3 appears only once.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q035'), 5, 'Multiply by 3:  2352 × 3 = 7056.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q035'), 6, '$\sqrt{7056} = 2^{2}$ × 3 × 7 = 84');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q035'), 7, 'Answer: multiply by 3; the square root is 84');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q036'), 1, 'Take each square root separately. Ask: which number, squared, gives this? Then check by squaring it back (p.13).');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q036'), 2, '$\sqrt{625}$ = 25');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q036'), 3, '$\sqrt{0.000625}$ = 0.025');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q036'), 4, '$\sqrt{0.0625}$ = 0.25');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q036'), 5, 'Sum = 25 + 0.025 + 0.25 = 25.275');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q036'), 6, 'Answer: 25.275');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q037'), 1, 'Use the rule $\sqrt[3]{a  \times  b}$ = ∛a × ∛b.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q037'), 2, '∛[$\left(18\right)^{3}  \times  \left(\frac{1}{12}\right)^{3}$] = $\sqrt[3]{18^{3}}  \times  \sqrt[3]{\left(\frac{1}{12}\right)^{3}}$');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q037'), 3, '= 18 × $\frac{1}{12}$');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q037'), 4, '= $\frac{18}{12} = \frac{3}{2}$');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q037'), 5, 'Answer: $\frac{3}{2}$ (= 1.5)');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q038'), 1, 'Group 19683 into threes from the right: 19 | 683.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q038'), 2, 'The last group ends in 3 ⇒ unit digit is 7 ($7^{3}$ = 343 ends in 3).');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q038'), 3, 'The first group 19 lies between $2^{3}$ = 8 and $3^{3}$ = 27 ⇒ tens digit 2.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q038'), 4, '$\sqrt[3]{19683}$ = 27');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q038'), 5, 'Answer: 27');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q039'), 1, 'Squaring a decimal doubles its decimal places (p.13), so a square root halves them. Check each by squaring back.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q039'), 2, '$\sqrt{3844}$ = 62, so $\sqrt{0.3844}$ = 0.62   (decimal moved 4 places left ⇒ root moved 2 places left)');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q039'), 3, '$\sqrt{32.49}$ = 5.7, so $\sqrt{0.003249}$ = 0.057   (decimal moved 4 places left ⇒ root moved 2 places left)');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q039'), 4, '0.62 - 0.057 = 0.563');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q039'), 5, 'Answer: 0.563');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q040'), 1, 'Prime factorise 17576 by repeated division by 2:');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q040'), 2, '17576 ÷ 2 = 8788, ÷ 2 = 4394, ÷ 2 = 2197. And 2197 = 13 × 169 = 13 × 13 × 13.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q040'), 3, 'So 17576 = $2^{3}  \times  13^{3}$.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q040'), 4, 'Group the primes in threes and take one from each group:');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q040'), 5, '$\sqrt[3]{17576}$ = 2 × 13 = 26');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q040'), 6, 'Answer: 26');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q041'), 1, '20 is not a perfect square, so we ESTIMATE by trapping it between squares and narrowing — the method the book uses for $\sqrt{1936}$ (p.9).');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q041'), 2, 'Step 1: $4^{2}$ = 16 and $5^{2}$ = 25, and 16 < 20 < 25, so $\sqrt{20}$ lies between 4 and 5.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q041'), 3, 'Step 2: narrow to one decimal place. $4.4^{2}$ = 19.36 (too small) and $4.5^{2}$ = 20.25 (too big), so $\sqrt{20}$ lies between 4.4 and 4.5.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q041'), 4, 'Step 3: narrow to two decimal places. $4.47^{2}$ = 19.9809 (just under 20) and $4.48^{2}$ = 20.0704 (just over 20).');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q041'), 5, 'So 20 lies between them, and 4.47 is the value correct to two decimal places.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q041'), 6, 'Answer: $\sqrt{20}$ ≈ 4.47');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q042'), 1, '⚠ The question asks for LONG DIVISION, which is not taught in your Ganita Prakash chapter. Solved here with a method you do have — if an exam insists on long division, ask your teacher.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q042'), 2, 'First clear the decimal:  691.69 = $\frac{69169}{100}$, so $\sqrt{691.69} = \sqrt{69169}$ ÷ 10.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q042'), 3, '69169 is awkward to prime factorise, so ESTIMATE instead — exactly as the book does for $\sqrt{1936}$ (p.9).');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q042'), 4, 'Step 1: trap it. $26^{2}$ = 676 and $27^{2}$ = 729, and 676 < 691.69 < 729, so the root lies between 26 and 27.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q042'), 5, 'Step 2: use the last digit. 691.69 ends in 9, and only $3^{2}$ = 9 and $7^{2}$ = 49 end in 9 — so the root ends in 3 or 7.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q042'), 6, 'Step 3: the candidates are 26.3 and 26.7. Since 691.69 is much closer to 676 than to 729, try the smaller one.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q042'), 7, 'Check: $26.3^{2}$ = 691.69 ✔');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q042'), 8, 'Answer: $\sqrt{691.69}$ = 26.3');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q043'), 1, '⚠ The question asks for LONG DIVISION, which is not taught in your Ganita Prakash chapter. Solved here with a method you do have — if an exam insists on long division, ask your teacher.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q043'), 2, 'First clear the decimal:  125.44 = $\frac{12544}{100}$, so $\sqrt{125.44} = \sqrt{12544}$ ÷ 10.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q043'), 3, 'Now find $\sqrt{12544}$ by PRIME FACTORISATION (p.9) — split the factors into two identical groups.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q043'), 4, '12544 = 2 × 6272 = 2 × 2 × 3136 = … keep dividing by 2:  12544 = $2^{8}  \times  7^{2}$');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q043'), 5, 'Split into two identical groups: 12544 = ($2^{4}$ × 7) × ($2^{4}$ × 7) = 112 × 112');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q043'), 6, 'So $\sqrt{12544}$ = 112, and $\sqrt{125.44}$ = 112 ÷ 10 = 11.2');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q043'), 7, 'Check: 11.2 × 11.2 = 125.44 ✔');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q043'), 8, 'Answer: $\sqrt{125.44}$ = 11.2');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q044'), 1, 'First clear the decimal:  2079.36 = $\frac{207936}{100}$, so $\sqrt{2079.36} = \sqrt{207936}$ ÷ 10.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q044'), 2, 'Prime factorise 207936 (p.9):  207936 = $2^{6}  \times  3^{2}  \times  19^{2}$');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q044'), 3, 'Split into two identical groups: ($2^{3}$ × 3 × 19) × ($2^{3}$ × 3 × 19) = 456 × 456');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q044'), 4, 'So $\sqrt{207936}$ = 456, and $\sqrt{2079.36}$ = 456 ÷ 10 = 45.6');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q044'), 5, 'Check by estimation too: $45^{2}$ = 2025 and $46^{2}$ = 2116, so the root is between 45 and 46 ✔, and 2079.36 ends in 6 so the root ends in 4 or 6 ✔');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q044'), 6, 'Answer: $\sqrt{2079.36}$ = 45.6');
