insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q045'), 2, 'First clear the decimal:  108.16 = $\frac{10816}{100}$, so $\sqrt{108.16} = \sqrt{10816}$ ÷ 10.');
