insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q046'), 2, 'First clear the decimal:  54.76 = $\frac{5476}{100}$, so $\sqrt{54.76} = \sqrt{5476}$ ÷ 10.');
